@app.route('/')
def home():
    search = request.args.get('search')   # search value tisukuntundi

    if search:
        filtered_products = []
        for p in products:
            if search.lower() in p['name'].lower():
                filtered_products.append(p)
    else:
        filtered_products = products

    return render_template("index.html", products=filtered_products)


@app.route('/add_to_cart/<name>')
def add_to_cart(name):
    for p in products:
        if p['name'] == name:
            cart_items.append(p)
    total = sum(item['price'] for item in cart_items)
    return render_template('cart.html', products=cart_items, total=total)


@app.route('/add_to_wishlist/<name>')
def add_to_wishlist(name):
    for p in products:
        if p['name'] == name:
            wishlist_items.append(p)
    return render_template('wishlist.html', products=wishlist_items)


@app.route('/cart')
def cart():
    total = sum(item['price'] for item in cart_items)
    return render_template('cart.html', products=cart_items, total=total)


@app.route('/wishlist')
def wishlist():
    return render_template('wishlist.html', products=wishlist_items)


if __name__ == '__main__':
    app.run(debug=True)

  